// core/tree/engine/TreeTraversal.ts

import type { TreeNode } from '../models/TreeNode';

export type TreePath = TreeNode[];

/**
 * Walks the tree depth-first and executes a callback for each node.
 */
export function walkTree(
  nodes: TreeNode[] | undefined,
  callback: (node: TreeNode, parent: TreeNode | null) => void,
  parent: TreeNode | null = null
): void {
  if (!nodes) return;

  for (const node of nodes) {
    callback(node, parent);

    if (node.children && node.children.length) {
      walkTree(node.children, callback, node);
    }
  }
}

/**
 * Finds a node by key.
 */
export function findNodeByKey(
  nodes: TreeNode[] | undefined,
  key: string
): TreeNode | null {
  let result: TreeNode | null = null;

  walkTree(nodes, (node) => {
    if (node.key === key) {
      result = node;
    }
  });

  return result;
}

/**
 * Finds a node and its full ancestor path.
 * Path order: root → ... → target
 */
export function findNodePath(
  nodes: TreeNode[] | undefined,
  key: string
): TreePath | null {
  if (!nodes) return null;

  for (const node of nodes) {
    if (node.key === key) {
      return [node];
    }

    if (node.children) {
      const childPath = findNodePath(node.children, key);
      if (childPath) {
        return [node, ...childPath];
      }
    }
  }

  return null;
}

/**
 * Returns all descendant nodes (deep).
 */
export function collectDescendants(node: TreeNode): TreeNode[] {
  const result: TreeNode[] = [];

  walkTree(node.children, (child) => {
    result.push(child);
  });

  return result;
}

/**
 * Returns all descendant keys (deep).
 */
export function collectDescendantKeys(node: TreeNode): string[] {
  return collectDescendants(node).map((n) => n.key);
}

/**
 * Returns all ancestor nodes (excluding the node itself).
 */
export function collectAncestors(
  nodes: TreeNode[] | undefined,
  key: string
): TreeNode[] {
  const path = findNodePath(nodes, key);
  if (!path) return [];

  // exclude target node itself
  return path.slice(0, path.length - 1);
}

/**
 * Returns all ancestor keys (excluding the node itself).
 */
export function collectAncestorKeys(
  nodes: TreeNode[] | undefined,
  key: string
): string[] {
  return collectAncestors(nodes, key).map((n) => n.key);
}
